SELECT
tri.template_id, tri.template_type, tri.user_id, tri.rule_name, tri.rule_content, 
tri.update_by, tri.create_time, tri.update_time
FROM template_rule_info tri

    INNER JOIN resource_template_relation rtr ON tri.template_id = rtr.template_id 
    AND rtr.resource_id = #{queryQo.resourceId}




        AND tri.template_id = #{queryQo.templateId}



        AND tri.user_id = #{queryQo.userId}



        AND tri.is_memory_template = #{queryQo.isMemoryTemplate}




        AND tri.rule_name LIKE CONCAT('%', #{queryQo.ruleName}, '%')



        AND tri.template_type = #{queryQo.templateType}



        AND tri.rule_content LIKE CONCAT('%', #{queryQo.ruleContent}, '%')



        AND tri.create_time >= #{queryQo.createTimeStart}


        AND tri.create_time <= #{queryQo.createTimeEnd}



        AND tri.update_time >= #{queryQo.updateTimeStart}


        AND tri.update_time <= #{queryQo.updateTimeEnd}


ORDER BY tri.create_time DESC, tri.update_time DESC

SELECT
tri.template_id as "templateId",
tri.template_type as "templateType",
tri.user_id as "userId",
tri.rule_name as "ruleName",
tri.rule_content as "ruleContent",
tri.update_by as "updateBy",
tri.create_time as "createTime",
tri.update_time as "updateTime",
rtr.memory_rule_id as "memoryRuleId"
FROM template_rule_info tri
INNER JOIN resource_template_relation rtr ON tri.template_id = rtr.template_id 
AND rtr.resource_id = #{queryQo.resourceId}



        AND tri.template_id = #{queryQo.templateId}



        AND tri.user_id = #{queryQo.userId}



        AND tri.is_memory_template = #{queryQo.isMemoryTemplate}



        AND tri.rule_name LIKE CONCAT('%', #{queryQo.ruleName}, '%')



        AND tri.template_type = #{queryQo.templateType}



        AND tri.rule_content LIKE CONCAT('%', #{queryQo.ruleContent}, '%')



        AND tri.create_time >= #{queryQo.createTimeStart}


        AND tri.create_time <= #{queryQo.createTimeEnd}



        AND tri.update_time >= #{queryQo.updateTimeStart}


        AND tri.update_time <= #{queryQo.updateTimeEnd}


ORDER BY tri.create_time DESC, tri.update_time DESC

SELECT memory_rule_id
FROM resource_template_relation
WHERE resource_id = #{resourceId}
